 get_symbol_summary(self, symbol: str) -> Dict[str, Any]:
        """Get comprehensive summary for a symbol."""
        fundamental = self.get_fundamental(symbol)
        technical = self.get_technical(symbol)
        signals = self.get_signals(symbol)

        latest_signal = signals[0] if signals else None

        return {
            "symbol": symbol,
            "fundamental_count": len(fundamental),
            "technical_count": len(technical),
            "signal_count": len(signals),
            "latest_signal": {
                "action": latest_signal.metadata.get("action"),
                "confidence": latest_signal.metadata.get("confidence"),
                "timestamp": latest_signal.timestamp
            } if latest_signal else None,
            "knowledge_types": {
                "fundamental": len(fundamental),
                "technical": len(technical),
                "signals": len(signals)
            }
        }

    def _format_fundamental_data(self, symbol: str, data: Dict) -> str:
        """Format fundamental data as readable text."""
        lines = [f"Fundamental Analysis for {symbol}"]
        lines.append("=" * 40)

        for key, value in data.items():
            if value is not None:
                lines.append(f"{key}: {value}")

        return "\n".join(lines)


